# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import urllib3
import base64

http = urllib3.PoolManager()

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    headers = request['headers']
    
    enriched_data = {}
    
    # Check for X-Enrich-URL header(s)
    if 'x-enrich-url' in headers:
        enrich_urls = headers['x-enrich-url']
        
        for url_header in enrich_urls:
            url = url_header['value']
            
            try:
                # Fetch data from the URL
                response = http.request('GET', url, timeout=2.0)
                
                if response.status == 200:
                    # Store the fetched data
                    enriched_data[url] = response.data.decode('utf-8')
                else:
                    enriched_data[url] = f"Error: HTTP {response.status}"
                    
            except Exception as e:
                enriched_data[url] = f"Error: {str(e)}"
    
    # Add enriched data to request headers as base64 encoded JSON
    if enriched_data:
        enriched_json = json.dumps(enriched_data)
        enriched_b64 = base64.b64encode(enriched_json.encode('utf-8')).decode('utf-8')
        
        # Add as custom header
        headers['x-enriched-data'] = [{
            'key': 'X-Enriched-Data',
            'value': enriched_b64
        }]
    
    return request